2	
3	module write_out#(
4		parameter ARRAY_SIZE = 8,
5		parameter OUTPUT_DATA_WIDTH = 16
6	)
7	(
8		input clk,
9		input srstn,
10		input sram_write_enable,
11	
12		input [1:0] data_set,
13		input [5:0] matrix_index,
14	
15		input signed [ARRAY_SIZE*OUTPUT_DATA_WIDTH-1:0] quantized_data,
16		
17		output reg sram_write_enable_a0,
18		output reg [ARRAY_SIZE*OUTPUT_DATA_WIDTH-1:0] sram_wdata_a,
19	 	output reg [5:0] sram_waddr_a,
20	
21		output reg sram_write_enable_b0,
22		output reg [ARRAY_SIZE*OUTPUT_DATA_WIDTH-1:0] sram_wdata_b,
23	 	output reg [5:0] sram_waddr_b,
24	
25		output reg sram_write_enable_c0,
26		output reg [ARRAY_SIZE*OUTPUT_DATA_WIDTH-1:0] sram_wdata_c,
27	 	output reg [5:0] sram_waddr_c
28	);
29	
30	integer i;
31	localparam MAX_INDEX = ARRAY_SIZE - 1;
32	
33	//output flip-flop
34	reg sram_write_enable_a0_nx;
35	reg sram_write_enable_b0_nx;
36	reg sram_write_enable_c0_nx;
37	
38	reg [ARRAY_SIZE*OUTPUT_DATA_WIDTH-1:0] sram_wdata_a_nx;
39	reg [ARRAY_SIZE*OUTPUT_DATA_WIDTH-1:0] sram_wdata_b_nx;
40	reg [ARRAY_SIZE*OUTPUT_DATA_WIDTH-1:0] sram_wdata_c_nx;
41	
42	reg [5:0] sram_waddr_a_nx;
43	reg [5:0] sram_waddr_b_nx;
44	reg [5:0] sram_waddr_c_nx;
45	
46	//---sequential logic-----
47	always@(posedge clk) begin
48		if(~srstn) begin
49			sram_write_enable_a0 <= 1;
50			sram_write_enable_b0 <= 1;
51			sram_write_enable_c0 <= 1;
52	
53			sram_wdata_a <= 0;
54			sram_wdata_b <= 0;
55			sram_wdata_c <= 0;
56	
57			sram_waddr_a <= 0;
58			sram_waddr_b <= 0;
59			sram_waddr_c <= 0;
60		end
61		else begin
62			sram_write_enable_a0 <= sram_write_enable_a0_nx;
63			sram_write_enable_b0 <= sram_write_enable_b0_nx;
64			sram_write_enable_c0 <= sram_write_enable_c0_nx;
65	
66			sram_wdata_a <= sram_wdata_a_nx;
67			sram_wdata_b <= sram_wdata_b_nx;
68			sram_wdata_c <= sram_wdata_c_nx;
69	
70			sram_waddr_a <= sram_waddr_a_nx;
71			sram_waddr_b <= sram_waddr_b_nx;
72			sram_waddr_c <= sram_waddr_c_nx;
73		end
74	end
75	
76	
77	//for a0, write_enable_X0 = 0 means write
78	always@(*) begin
79		if(sram_write_enable) begin
80			case(data_set)
81				0: begin
82					if(matrix_index < ARRAY_SIZE) begin
83						sram_write_enable_a0_nx = 0;
84						for(i=0; i<ARRAY_SIZE; i=i+1) begin
85							if(i<=matrix_index)
86								sram_wdata_a_nx[(MAX_INDEX-i)*OUTPUT_DATA_WIDTH +: OUTPUT_DATA_WIDTH] = quantized_data[i*OUTPUT_DATA_WIDTH +: OUTPUT_DATA_WIDTH];
87							else
88								sram_wdata_a_nx[(MAX_INDEX-i)*OUTPUT_DATA_WIDTH +: OUTPUT_DATA_WIDTH] = 0;
89						end
90						sram_waddr_a_nx = matrix_index;
91					end
